mapper.select:
SELECT notification_id, user_id, sender_id, group_id, type, target_id, message, is_read, created_at
FROM notifications
WHERE notification_id = #{notificationId}

mapper.update:
UPDATE notifications
SET is_read = TRUE
WHERE notification_id = #{notificationId}

mapper.delete:
DELETE FROM notifications
WHERE user_id = #{userId}
  AND sender_id = #{senderId}
  AND group_id = #{groupId}
  AND type = #{type}
